client_script:
frappe.web_form.on('load', function(){
  var user = (frappe.session && frappe.session.user) ? frappe.session.user : null;
  if (!user || user === 'Guest') return;

  if (!frappe.web_form.doc.date_ao) {
    frappe.web_form.set_value('date_ao', frappe.datetime.get_today());
  }
  if (!frappe.web_form.doc.date_limite) {
    frappe.web_form.set_value('date_limite', frappe.datetime.add_days(frappe.datetime.get_today(), 7));
  }

  frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'Employee',
      filters: { user_id: user, status: 'Active' },
      fieldname: ['name', 'employee_name', 'department']
    },
    callback: function(r){
      if (!r || !r.message) return;
      if (!frappe.web_form.doc.demandeur) {
        frappe.web_form.set_value('demandeur', r.message.name);
      }
      if (r.message.employee_name && !frappe.web_form.doc.demandeur_name) {
        frappe.web_form.set_value('demandeur_name', r.message.employee_name);
      }
      if (r.message.department && !frappe.web_form.doc.service) {
        frappe.web_form.set_value('service', r.message.department);
      }
    }
  });
});
